 */
export function getUserDb(jwt: string) {
  return createClient(supabaseUrl, supabaseAnonKey, {
    db: {
      schema: dbSchema
    },
    global: {
      headers: {
        Authorization: `Bearer ${jwt}`
      }
    }
  })
}

/**
 * @chunk-id    ACCOUNT_NODES_HANDLER_1_0_0
 * @version     1.0.0
 * @hash        0778bcec10cfbe1a79177e4352706270194cf80cd0baa39c6ed615c73c7c7695
 * @macro       Account Hierarchy Handler
 * @micro       Returns account node with ancestors, children, and descendants
 * @inputs      ctx: CoreContext — Request context with principal and database
 * @inputs      body: any — Request body (unused for GET)
 * @outputs     {node, ancestors, children, descendants} — Complete hierarchy data
 * @depends-on  [createHandler, get_account_ancestors, get_account_descendants]
 * @depended-by [Netlify function routing]
 * @side-effects [DB queries, RPC calls]
 * @tags        account, hierarchy, netlify-function, api
 */
export const handler = createHandler(async (ctx, body) => {
  const { node_id } = ctx.query || {}

  if (!node_id) {
    throw new Error('node_id is required')
  }

  // Get the account node
  const { data: node, error: nodeError } = await ctx.db
    .from('accounts')
    .select(`
      *,
      type:types(id, slug, name, icon, color)
    `)
    .eq('id', node_id)
    .eq('is_active', true)
    .single()

  if (nodeError || !node) {
    throw new Error('Account node not found')
  }

  // Get ancestors using the closure table
  const { data: ancestors, error: ancestorsError } = await ctx.db
    .rpc('get_account_ancestors', { account_id: node_id })

  if (ancestorsError) {
    throw ancestorsError
  }

  // Get children (direct descendants)
  const { data: children, error: childrenError } = await ctx.db
    .from('accounts')
    .select(`
      *,
      type:types(id, slug, name, icon, color)
    `)
    .eq('parent_id', node_id)
    .eq('is_active', true)
    .order('display_name')

  if (childrenError) {
    throw childrenError
  }

  // Get all descendants (optional, for tree view)
  const { data: descendants, error: descendantsError } = await ctx.db
    .rpc('get_account_descendants', { account_id: node_id })

  if (descendantsError) {
    throw descendantsError
  }

  return {
    node,
    ancestors: ancestors || [],
    children: children || [],
    descendants: descendants || []
  }
})

/**
 * @chunk-id    ADMIN_DATA_LIST_1_0_0
 * @version     1.0.0
 * @hash        780f1f0c81ea3bff78d40970ba4b03e3211d892bb883e6a099c6e0a55ee53b0c
 * @macro       Entity List Handler
 * @micro       Lists records with filtering, search, sorting, and pagination
 * @inputs      ctx: CoreContext — Request context with principal and database
 * @inputs      _body: any — Request body (unused for GET)
 * @outputs     Array of sanitized records or {data, schema, view} with view config
 * @depends-on  [createHandler, sanitizeRecordData, adminDb, getSearchField]
 * @depended-by [Netlify function routing]
 * @side-effects [DB queries, permission sanitization]
 * @tags        admin, crud, list, pagination, search
 */
export const list = createHandler(async (ctx, _body) => {
  // Extract all reserved query params to prevent them from being used as column filters
  const { entity, action, method, search, sort_field = 'created_at', sort_direction = 'desc', limit = 50, offset = 0, type_slug, view: viewSlug, ...filters } = ctx.query || {}

  if (!entity || !VALID_ENTITIES.includes(entity)) {
    throw new Error('Valid entity parameter is required')
  }

  // Use ctx.db - RLS-scoped client based on principal
  // RLS policies enforce account hierarchy access automatically
  let query = ctx.db.from(entity).select('*')

  // Apply type_slug filter if provided (for schema-driven entities)
  if (type_slug && entity === 'items') {
    // Look up the type ID from the slug
    const { data: typeRecord } = await adminDb
      .from('types')
      .select('id')
      .eq('slug', type_slug)
      .eq('is_active', true)
      .single()

    if (typeRecord) {
      query = query.eq('type_id', typeRecord.id)
    }
  }

  // Apply search if provided
  if (search) {
    // Search in display field based on entity
    const searchField = getSearchField(entity)
    query = query.ilike(searchField, `%${search}%`)
  }

  // Apply filters
  Object.entries(filters).forEach(([key, value]) => {
    if (value !== undefined && value !== null && value !== '') {
      if (key === 'is_active' || key === 'is_verified' || key === 'is_primary') {
        query = query.eq(key, value === 'true')
      } else {
        query = query.eq(key, value)
      }
    }
  })

  // Apply sorting
  query = query.order(sort_field, { ascending: sort_direction === 'asc' })

  // Get total count (RLS filters automatically)
  const { count, error: countError } = await ctx.db.from(entity)
    .select('*', { count: 'exact', head: true })

  if (countError) {
    console.error('List count error:', countError)
    throw new Error(countError.message || 'Database error getting count')
  }

  // Apply pagination
  query = query.range(parseInt(offset.toString()), parseInt(offset.toString()) + parseInt(limit.toString()) - 1)

  const { data, error: err } = await query

  if (err) {
    console.error('List query error:', err)
    throw new Error(err.message || 'Database error listing records')
  }

  // RLS policies already filtered the data - just sanitize
  const sanitizedData = []
  for (const record of data || []) {
    const sanitizedRecord = await sanitizeRecordData(ctx, record, entity)
    sanitizedData.push(sanitizedRecord)
  }

  // If ?view=slug was requested, resolve schema + view config from the type record
  if (viewSlug && type_slug) {
    const { data: typeRecord } = await adminDb
      .from('types')
      .select('design_schema')
      .eq('slug', type_slug)
      .eq('is_active', true)
      .single()

    if (typeRecord?.design_schema) {
      const schema = typeRecord.design_schema
      const resolvedView = schema.views?.[viewSlug] || null
      return { data: sanitizedData, schema, view: resolvedView }
    }
  }

  return sanitizedData
})

/**
 * @chunk-id    ADMIN_DATA_GET_1_0_0
 * @version     1.0.0
 * @hash        7ee27702615d7ebd144e065d399635ddf7664845685345d8a8f316449f11a7cf
 * @macro       Entity Get Handler
 * @micro       Returns a single record by ID with optional view configuration
 * @inputs      ctx: CoreContext — Request context with principal and database
 * @inputs      _body: any — Request body (unused for GET)
 * @outputs     Sanitized record or {data, schema, view} with view config
 * @depends-on  [createHandler, sanitizeRecordData]
 * @depended-by [Netlify function routing]
 * @side-effects [DB single row query, permission sanitization]
 * @tags        admin, crud, get, single-record
 */
export const get = createHandler(async (ctx, _body) => {
  const { entity, id, view: viewSlug } = ctx.query || {}

  if (!entity || !VALID_ENTITIES.includes(entity)) {
    throw new Error('Valid entity parameter is required')
  }

  if (!id) {
    throw new Error('ID parameter is required')
  }

  // RLS will filter based on account hierarchy access
  const { data, error: err } = await ctx.db.from(entity)
    .select('*')
    .eq('id', id)
    .single()

  if (err) throw err

  if (!data) {
    throw new Error('Record not found')
  }

  const sanitizedRecord = await sanitizeRecordData(ctx, data, entity)

  // If ?view=slug was requested, include schema + resolved view from the record's stamped schema
  if (viewSlug && sanitizedRecord?.design_schema) {
    const schema = sanitizedRecord.design_schema
    const resolvedView = schema.views?.[viewSlug] || null
    return { data: sanitizedRecord, schema, view: resolvedView }
  }

  return sanitizedRecord
})

/**
 * @chunk-id    ADMIN_DATA_STATS_1_0_0
 * @version     1.0.0
 * @hash        0bed523a260ab3959cb4e7150cca044f4e97ce91d7ae3386ab14b5f4182d74d7
 * @macro       Entity Stats Handler
 * @micro       Returns total record count for an entity scoped by account
 * @inputs      ctx: CoreContext — Request context with principal and database
 * @inputs      _body: any — Request body (unused for GET)
 * @outputs     {entity: string, count: number} — Entity name and record count
 * @depends-on  [createHandler]
 * @depended-by [Netlify function routing]
 * @side-effects [DB count query with RLS filtering]
 * @tags        admin, stats, count, entity
 */
export const stats = createHandler(async (ctx, _body) => {
  const { entity } = ctx.query || {}

  if (!entity || !VALID_ENTITIES.includes(entity)) {
    throw new Error('Valid entity parameter is required')
  }

  // RLS will filter count based on account hierarchy access
  const { count, error: err } = await ctx.db.from(entity)
    .select('*', { count: 'exact', head: true })

  if (err) throw err

  return { entity, count }
})

/**
 * @chunk-id    ADMIN_DATA_HANDLER_1_0_0
 * @version     1.0.0
 * @hash        edceffa0d5c8b3c05b1a89188a274a586b6ebe8793ede427e2326876d7090df9
 * @macro       Admin Data Router
 * @micro       Routes HTTP methods and actions to appropriate CRUD handlers
 * @inputs      ctx: CoreContext — Request context with principal and database
 * @inputs      body: any — Request body for POST/PATCH operations
 * @outputs     Varies — Depends on routed handler (list/get/create/update/remove/stats)
 * @depends-on  [createHandler, list, get, create, update, remove, stats]
 * @depended-by [Netlify function routing]
 * @side-effects [Delegates to appropriate handler]
 * @tags        admin, router, crud, netlify-function
 */
export const handler = createHandler(async (ctx, body) => {
  const { action } = ctx.query || {}
  const method = ctx.query?.method || 'GET'

  switch (action) {
    case 'list':
      if (method === 'GET') {
        return await list(ctx, body)
      }
      break
    case 'get':
      if (method === 'GET') {
        return await get(ctx, body)
      }
      break
    case 'stats':
      if (method === 'GET') {
        return await stats(ctx, body)
      }
      break
    default:
      if (method === 'GET' && ctx.query?.id) {
        return await get(ctx, body)
      } else if (method === 'GET') {
        return await list(ctx, body)
      } else if (method === 'POST') {
        return await create(ctx, body)
      } else if (method === 'PATCH') {
        return await update(ctx, body)
      } else if (method === 'DELETE') {
        return await remove(ctx, body)
      }
  }

  throw new Error('Invalid action or method')
})

/**
 * @chunk-id    AI_AGENTS_LIST_1_0_0
 * @version     1.0.0
 * @hash        237972d65e86f5d432f55b602ac5e6f2dcfaefa83c662c10b7d3437ac906ff0d
 * @macro       AI Agents List Handler
 * @micro       Lists AI agents with filtering and pagination
 * @inputs      ctx: CoreContext — Request context with principal and database
 * @inputs      _body: any — Request body (unused for GET)
 * @outputs     Array of sanitized AI agent records
 * @depends-on  [createHandler, joins, sanitizeRecordData]
 * @depended-by [Netlify function routing]
 * @side-effects [DB queries, permission sanitization]
 * @tags        ai-agents, list, crud, pagination
 */
export const list = createHandler(async (ctx, _body) => {
  const { agent_type, is_active, limit = 100, offset = 0 } = ctx.query || {}

  if (!ctx.accountId) {
    throw new Error('Account context required')
  }

  // RLS automatically filters to accessible accounts
  let query = ctx.db
    .from('ai_agents')
    .select(`*, ${joins.app}, ${joins.createdBy}`)
    .order('name')

  if (agent_type) {
    query = query.eq('agent_type', agent_type)
  }
  if (is_active !== undefined) {
    query = query.eq('is_active', is_active === 'true')
  }

  const { data, error: err } = await query.range(
    parseInt(offset.toString()),
    parseInt(offset.toString()) + parseInt(limit.toString()) - 1
  )

  if (err) throw err

  const sanitized = []
  for (const agent of data || []) {
    sanitized.push(await sanitizeRecordData(ctx, agent, 'ai_agent'))
  }

  return sanitized
})

/**
 * @chunk-id    AI_AGENTS_UPDATE_1_0_0
 * @version     1.0.0
 * @hash        07e173626958a0ef032cc4c80719c49df5990756e08ecdb70a4168ab73544f10
 * @macro       AI Agent Update Handler
 * @micro       Updates AI agent with field validation and audit logging
 * @inputs      ctx: CoreContext — Request context with principal and database
 * @inputs      body: object — Agent updates including id
 * @outputs     Updated AI agent record
 * @depends-on  [createHandler, emitLog]
 * @depended-by [Netlify function routing]
 * @side-effects [DB update, audit logging]
 * @tags        ai-agents, update, crud, audit
 */
export const update = createHandler(async (ctx, body) => {
  const id = body?.id || ctx.query?.id
  const { id: _bodyId, ...updates } = body || {}

  if (!id) {
    throw new Error('Agent ID is required')
  }

  if (!ctx.principal || ctx.principal.id === 'anonymous' || !ctx.accountId) {
    throw new Error('User context (person and account) required')
  }

  const allowed = ['name', 'description', 'model_config', 'system_prompt', 'tools', 'capabilities', 'constraints', 'metadata', 'is_active']
  const updateData: Record<string, any> = { updated_at: new Date().toISOString() }
  for (const key of allowed) {
    if (updates[key] !== undefined) updateData[key] = updates[key]
  }

  const { data, error: err } = await ctx.db
    .from('ai_agents')
    .update(updateData)
    .eq('id', id)
    .select()
    .single()

  if (err) throw err

  await emitLog(ctx, 'ai_agent.updated', 
    { type: 'ai_agent', id }, 
    { after: updateData }
  )

  return data
})

/**
 * @chunk-id    AI_AGENTS_HANDLER_1_0_0
 * @version     1.0.0
 * @hash        a49f4917dd07295e0ba9815bf929cccc5cffcbe4dcf6852aa4bd84d6cba1b690
 * @macro       AI Agents Router
 * @micro       Routes HTTP methods to appropriate CRUD handlers
 * @inputs      ctx: CoreContext — Request context with principal and database
 * @inputs      body: any — Request body for POST/PATCH operations
 * @outputs     Varies — Depends on routed handler (list/get/create/update/remove)
 * @depends-on  [createHandler, list, get, create, update, remove]
 * @depended-by [Netlify function routing]
 * @side-effects [Delegates to appropriate handler]
 * @tags        ai-agents, router, crud, netlify-function
 */
export const handler = createHandler(async (ctx, body) => {
  const { action } = ctx.query || {}
  const method = ctx.query?.method || 'GET'

  switch (action) {
    default:
      if (method === 'GET') {
        if (ctx.query?.id) {
          return await get(ctx, body)
        } else {
          return await list(ctx, body)
        }
      } else if (method === 'POST') {
        return await create(ctx, body)
      } else if (method === 'PATCH') {
        return await update(ctx, body)
      } else if (method === 'DELETE') {
        return await remove(ctx, body)
      }
  }

  throw new Error('Invalid action or method')
})

/**
 * @chunk-id    API_KEYS_LIST_1_0_0
 * @version     1.0.0
 * @hash        f825d8f4bbabe21071b61fe41e5e4e1b87482d501bf4078fab70906b7a5f5e78
 * @macro       API Keys List Handler
 * @micro       Lists API keys with filtering, pagination, and joins
 * @inputs      ctx: CoreContext — Request context with principal and database
 * @inputs      _body: any — Request body (unused for GET)
 * @outputs     Array of sanitized API key records with integration joins
 * @depends-on  [createHandler, sanitizeRecordData]
 * @depended-by [Netlify function routing]
 * @side-effects [DB queries, permission sanitization]
 * @tags        api-keys, list, crud, pagination
 */
export const list = createHandler(async (ctx, _body) => {
  const { integration_id, key_type, is_active, expires_before, expires_after, limit = 100, offset = 0 } = ctx.query || {}

  if (!ctx.accountId) {
    throw new Error('Account context required')
  }

  let query = ctx.db
    .from('api_keys')
    .select(`
      *,
      integration:integrations(id, name, provider, integration_type),
      created_by_person:people(id, full_name, email)
    `)
    .order('created_at', { ascending: false })

  if (integration_id) {
    query = query.eq('integration_id', integration_id)
  }
  if (key_type) {
    query = query.eq('key_type', key_type)
  }
  if (is_active !== undefined) {
    query = query.eq('is_active', is_active === 'true')
  }
  if (expires_before) {
    query = query.lte('expires_at', expires_before)
  }
  if (expires_after) {
    query = query.gte('expires_at', expires_after)
  }

  const { data, error: err } = await query.range(
    parseInt(offset.toString()),
    parseInt(offset.toString()) + parseInt(limit.toString()) - 1
  )

  if (err) throw err

  const sanitized = []
  for (const key of data || []) {
    sanitized.push(await sanitizeRecordData(ctx, key, 'api_key'))
  }

  return sanitized
})

/**
 * @chunk-id    API_KEYS_LIST_USAGE_LOGS_1_0_0
 * @version     1.0.0
 * @hash        f21e004490dd983c8f20dc1d1f4db33e158334d19e38a4ace5e99389a8a96ded
 * @macro       API Key Usage Logs Handler
 * @micro       Lists paginated API key usage logs with filtering and joins
 * @inputs      ctx: CoreContext — Request context with principal and database
 * @inputs      _body: any — Request body (unused for GET)
 * @outputs     Array of usage log records with api_key joins
 * @depends-on  [createHandler]
 * @depended-by [Netlify function routing]
 * @side-effects [DB queries with filtering]
 * @tags        api-keys, usage-logs, pagination, monitoring
 */
export const listUsageLogs = createHandler(async (ctx, _body) => {
  const { api_key_id, response_status, success, date_from, date_to, limit = 100, offset = 0 } = ctx.query || {}

  if (!ctx.accountId) {
    throw new Error('Account context required')
  }

  let query = ctx.db
    .from('api_key_usage_logs')
    .select(`
      *,
      api_key:api_keys(id, name, key_type)
    `)
    .order('created_at', { ascending: false })

  if (api_key_id) {
    query = query.eq('api_key_id', api_key_id)
  }
  if (response_status) {
    query = query.eq('response_status', parseInt(response_status.toString()))
  }
  if (success !== undefined) {
    query = query.eq('success', success === 'true')
  }
  if (date_from) {
    query = query.gte('created_at', date_from)
  }
  if (date_to) {
    query = query.lte('created_at', date_to)
  }

  const { data, error: err } = await query.range(
    parseInt(offset.toString()),
    parseInt(offset.toString()) + parseInt(limit.toString()) - 1
  )

  if (err) throw err

  return data
})

/**
 * @chunk-id    API_KEYS_HANDLER_1_0_0
 * @version     1.0.0
 * @hash        6c2da419bea6f12b0fe654e2aad6c5ebac3d5993c2547a47d239f44197d90a68
 * @macro       API Keys Router
 * @micro       Routes HTTP methods and actions to appropriate handlers
 * @inputs      ctx: CoreContext — Request context with principal and database
 * @inputs      body: any — Request body for POST operations
 * @outputs     Varies — Depends on routed handler (list/get/create/validate/revoke/usage-logs)
 * @depends-on  [createHandler, list, get, create, validate, revoke, listUsageLogs]
 * @depended-by [Netlify function routing]
 * @side-effects [Delegates to appropriate handler]
 * @tags        api-keys, router, crud, netlify-function
 */
export const handler = createHandler(async (ctx, body) => {
  const { action } = ctx.query || {}
  const method = ctx.query?.method || 'GET'

  switch (action) {
    case 'validate':
      if (method === 'POST') {
        return await validate(ctx, body)
      }
      break
    case 'revoke':
      if (method === 'POST') {
        return await revoke(ctx, body)
      }
      break
